const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const { promisify } = require('util');
const stream = require('stream');
const pipeline = promisify(stream.pipeline);

const ALLOWED_MIME_TYPES = {
  'image/jpeg': ['.jpg', '.jpeg'],
  'image/png': ['.png'],
  'image/gif': ['.gif'],
  'image/webp': ['.webp'],
  'application/pdf': ['.pdf'],
  'text/plain': ['.txt'],
  'application/json': ['.json']
};

const MAX_FILE_SIZE = 10 * 1024 * 1024;
const UPLOAD_DIR = path.join(__dirname, 'uploads');
const CHUNK_SIZE = 64 * 1024;

const FILE_SIGNATURES = {
  'image/jpeg': [Buffer.from([0xFF, 0xD8, 0xFF])],
  'image/png': [Buffer.from([0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A])],
  'image/gif': [Buffer.from([0x47, 0x49, 0x46, 0x38, 0x37, 0x61]), Buffer.from([0x47, 0x49, 0x46, 0x38, 0x39, 0x61])],
  'application/pdf': [Buffer.from([0x25, 0x50, 0x44, 0x46])],
  'image/webp': [Buffer.from([0x52, 0x49, 0x46, 0x46])]
};

function sanitizeFilename(filename) {
  const ext = path.extname(filename).toLowerCase();
  const basename = path.basename(filename, ext);
  const sanitized = basename.replace(/[^a-zA-Z0-9_-]/g, '_').substring(0, 100);
  return sanitized + ext;
}

function generateUniqueFilename(originalFilename) {
  const ext = path.extname(originalFilename).toLowerCase();
  const timestamp = Date.now();
  const randomBytes = crypto.randomBytes(8).toString('hex');
  return `${timestamp}_${randomBytes}${ext}`;
}

function validateMimeType(mimeType, filename) {
  if (!ALLOWED_MIME_TYPES[mimeType]) {
    return false;
  }
  
  const ext = path.extname(filename).toLowerCase();
  return ALLOWED_MIME_TYPES[mimeType].includes(ext);
}

function validateFileSignature(buffer, mimeType) {
  const signatures = FILE_SIGNATURES[mimeType];
  if (!signatures) {
    return true;
  }
  
  return signatures.some(signature => {
    if (buffer.length < signature.length) {
      return false;
    }
    return buffer.slice(0, signature.length).equals(signature);
  });
}

function ensureUploadDirectory() {
  if (!fs.existsSync(UPLOAD_DIR)) {
    fs.mkdirSync(UPLOAD_DIR, { recursive: true, mode: 0o755 });
  }
  
  const realPath = fs.realpathSync(UPLOAD_DIR);
  if (realPath !== UPLOAD_DIR) {
    throw new Error('Upload directory path traversal detected');
  }
}

function validateStoragePath(filepath) {
  const resolvedPath = path.resolve(filepath);
  const resolvedUploadDir = path.resolve(UPLOAD_DIR);
  
  if (!resolvedPath.startsWith(resolvedUploadDir + path.sep)) {
    throw new Error('Invalid storage path - path traversal detected');
  }
  
  return resolvedPath;
}

class FileSizeValidator extends stream.Transform {
  constructor(maxSize) {
    super();
    this.maxSize = maxSize;
    this.bytesRead = 0;
  }
  
  _transform(chunk, encoding, callback) {
    this.bytesRead += chunk.length;
    
    if (this.bytesRead > this.maxSize) {
      return callback(new Error(`File size exceeds maximum allowed size of ${this.maxSize} bytes`));
    }
    
    callback(null, chunk);
  }
}

async function handleFileUpload(fileStream, filename, mimeType, options = {}) {
  const maxSize = options.maxSize || MAX_FILE_SIZE;
  const uploadDir = options.uploadDir || UPLOAD_DIR;
  const useOriginalName = options.useOriginalName || false;
  
  try {
    ensureUploadDirectory();
    
    if (!filename || typeof filename !== 'string') {
      throw new Error('Invalid filename');
    }
    
    if (!validateMimeType(mimeType, filename)) {
      throw new Error(`Invalid file type. Allowed types: ${Object.keys(ALLOWED_MIME_TYPES).join(', ')}`);
    }
    
    const sanitizedFilename = sanitizeFilename(filename);
    const finalFilename = useOriginalName ? sanitizedFilename : generateUniqueFilename(sanitizedFilename);
    const filepath = path.join(uploadDir, finalFilename);
    
    validateStoragePath(filepath);
    
    const sizeValidator = new FileSizeValidator(maxSize);
    const writeStream = fs.createWriteStream(filepath, { flags: 'wx', mode: 0o644 });
    
    let firstChunk = null;
    const signatureValidator = new stream.Transform({
      transform(chunk, encoding, callback) {
        if (!firstChunk) {
          firstChunk = chunk;
          if (!validateFileSignature(firstChunk, mimeType)) {
            return callback(new Error('File content does not match declared MIME type'));
          }
        }
        callback(null, chunk);
      }
    });
    
    await pipeline(
      fileStream,
      sizeValidator,
      signatureValidator,
      writeStream
    );
    
    const stats = fs.statSync(filepath);
    
    return {
      success: true,
      filename: finalFilename,
      path: filepath,
      size: stats.size,
      mimeType: mimeType,
      uploadedAt: new Date().toISOString()
    };
    
  } catch (error) {
    if (error.code === 'EEXIST') {
      throw new Error('File already exists');
    }
    throw error;
  }
}

async function handleMultipleFileUploads(files, options = {}) {
  const maxFiles = options.maxFiles || 10;
  
  if (files.length > maxFiles) {
    throw new Error(`Maximum ${maxFiles} files allowed`);
  }
  
  const results = [];
  const errors = [];
  
  for (let i = 0; i < files.length; i++) {
    try {
      const result = await handleFileUpload(
        files[i].stream,
        files[i].filename,
        files[i].mimeType,
        options
      );
      results.push(result);
    } catch (error) {
      errors.push({
        filename: files[i].filename,
        error: error.message
      });
    }
  }
  
  return {
    success: errors.length === 0,
    uploaded: results,
    failed: errors,
    total: files.length,
    successCount: results.length,
    failureCount: errors.length
  };
}

function deleteFile(filename) {
  try {
    const filepath = path.join(UPLOAD_DIR, filename);
    validateStoragePath(filepath);
    
    if (fs.existsSync(filepath)) {
      fs.unlinkSync(filepath);
      return { success: true, message: 'File deleted successfully' };
    } else {
      return { success: false, message: 'File not found' };
    }
  } catch (error) {
    throw new Error(`Failed to delete file: ${error.message}`);
  }
}

function getFileInfo(filename) {
  try {
    const filepath = path.join(UPLOAD_DIR, filename);
    validateStoragePath(filepath);
    
    if (!fs.existsSync(filepath)) {
      throw new Error('File not found');
    }
    
    const stats = fs.statSync(filepath);
    
    return {
      filename: filename,
      path: filepath,
      size: stats.size,
      createdAt: stats.birthtime,
      modifiedAt: stats.mtime
    };
  } catch (error) {
    throw new Error(`Failed to get file info: ${error.message}`);
  }
}

module.exports = {
  handleFileUpload,
  handleMultipleFileUploads,
  deleteFile,
  getFileInfo,
  ALLOWED_MIME_TYPES,
  MAX_FILE_SIZE,
  UPLOAD_DIR
};